// 定义发送登录接口请求方法
function sendLoginRequest() {
  const baseUrl = pm.globals.get("GATE_WAY");
  const username = pm.globals.get("LOGIN_USERNAME");
  const password = pm.globals.get("LOGIN_PASSWORD");
  
  const clientId = "qianyi";
  const clientSecret = "qianyi";
  const credentials = `${clientId}:${clientSecret}`;
  const encodedCredentials = Buffer.from(credentials).toString("base64");

  const loginRequest = {
    url: baseUrl + "/auth/oauth2/token",
    method: "POST",
	header: {
        "Content-Type": "application/x-www-form-urlencoded",
        //"Authorization": "Basic " + btoa("qianyi:qianyi") // Base64 编码
		"Authorization": "Basic " + encodedCredentials // Base64 编码
    },
    body: {
        mode: "urlencoded",
        urlencoded: [
            { key: "grant_type", value: "password" },
            { key: "username", value: username },
            { key: "password", value: password },
            { key: "scope", value: "server" }
        ]
    }
  };

  pm.sendRequest(loginRequest, function(err, res) {
    if (err) {
      console.log(err);
    } else {
      const jsonData = res.json();
      pm.environment.set("ACCESS_TOKEN", jsonData.access_token);
      pm.environment.set("ACCESS_TOKEN_EXPIRES", jsonData.exp * 1000);
    }
  });
}

const accessToken = pm.environment.get("ACCESS_TOKEN");
const accessTokenExpires = pm.environment.get("ACCESS_TOKEN_EXPIRES");
if (!accessToken || (accessTokenExpires && accessTokenExpires <= Date.now())) {
  sendLoginRequest();
}
